(1, 1, 1, 'order_created', 'order', 'Prueba de variables Twig - Pedido Creado', 'Prueba de variables Twig - Pedido Creado', 'mailsendvx_default', '<div class=\"header\">\r\n      <h1>Prueba de variables Twig</h1>\r\n      <p>Template de evento: {{ event.name }}</p>\r\n    </div>\r\n\r\n    <div class=\"section\">\r\n      <h2>Evento</h2>\r\n\r\n      <table>\r\n        <thead>\r\n          <tr>\r\n            <th>Nombre de la variable</th>\r\n            <th>Variable Twig</th>\r\n          </tr>\r\n        </thead>\r\n        <tbody>\r\n          <tr>\r\n            <td>event.name</td>\r\n            <td>{{ event.name }}</td>\r\n          </tr>\r\n        </tbody>\r\n      </table>\r\n    </div>\r\n\r\n    <div class=\"section\">\r\n      <h2>Tienda</h2>\r\n\r\n      <table>\r\n        <thead>\r\n          <tr>\r\n            <th>Nombre de la variable</th>\r\n            <th>Variable Twig</th>\r\n          </tr>\r\n        </thead>\r\n        <tbody>\r\n          <tr>\r\n            <td>shop.id</td>\r\n            <td>{{ shop.id }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>shop.id_lang</td>\r\n            <td>{{ shop.id_lang }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>shop.name</td>\r\n            <td>{{ shop.name }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>shop.url</td>\r\n            <td>{{ shop.url }}</td>\r\n          </tr>\r\n        </tbody>\r\n      </table>\r\n    </div>\r\n\r\n    <div class=\"section\">\r\n      <h2>Cliente</h2>\r\n\r\n      <table>\r\n        <thead>\r\n          <tr>\r\n            <th>Nombre de la variable</th>\r\n            <th>Variable Twig</th>\r\n          </tr>\r\n        </thead>\r\n        <tbody>\r\n          <tr>\r\n            <td>customer.id</td>\r\n            <td>{{ customer.id }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>customer.name</td>\r\n            <td>{{ customer.name }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>customer.firstname</td>\r\n            <td>{{ customer.firstname }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>customer.lastname</td>\r\n            <td>{{ customer.lastname }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>customer.email</td>\r\n            <td>{{ customer.email }}</td>\r\n          </tr>\r\n        </tbody>\r\n      </table>\r\n    </div>\r\n\r\n    <div class=\"section\">\r\n      <h2>Pedido</h2>\r\n\r\n      <table>\r\n        <thead>\r\n          <tr>\r\n            <th>Nombre de la variable</th>\r\n            <th>Variable Twig</th>\r\n          </tr>\r\n        </thead>\r\n        <tbody>\r\n          <tr>\r\n            <td>order.id</td>\r\n            <td>{{ order.id }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.reference</td>\r\n            <td>{{ order.reference }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.total</td>\r\n            <td>{{ order.total }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.date</td>\r\n            <td>{{ order.date }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.formated_date</td>\r\n            <td>{{ order.formated_date }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.status</td>\r\n            <td>{{ order.status }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.old_status</td>\r\n            <td>{{ order.old_status }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.payment_method</td>\r\n            <td>{{ order.payment_method }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.shipping_method</td>\r\n            <td>{{ order.shipping_method }}</td>\r\n          </tr>\r\n        </tbody>\r\n      </table>\r\n    </div>\r\n\r\n    <div class=\"section\">\r\n      <h2>Estado del pedido</h2>\r\n\r\n      <table>\r\n        <thead>\r\n          <tr>\r\n            <th>Nombre de la variable</th>\r\n            <th>Variable Twig</th>\r\n          </tr>\r\n        </thead>\r\n        <tbody>\r\n          <tr>\r\n            <td>order.state.id</td>\r\n            <td>{{ order.state.id }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.state.key</td>\r\n            <td>{{ order.state.key }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.state.name</td>\r\n            <td>{{ order.state.name }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.old_state.id</td>\r\n            <td>{{ order.old_state.id }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.old_state.key</td>\r\n            <td>{{ order.old_state.key }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.old_state.name</td>\r\n            <td>{{ order.old_state.name }}</td>\r\n          </tr>\r\n        </tbody>\r\n      </table>\r\n    </div>\r\n\r\n    <div class=\"section\">\r\n      <h2>Totales del pedido</h2>\r\n\r\n      <table>\r\n        <thead>\r\n          <tr>\r\n            <th>Nombre de la variable</th>\r\n            <th>Variable Twig</th>\r\n          </tr>\r\n        </thead>\r\n        <tbody>\r\n          <tr>\r\n            <td>order.totals.paid</td>\r\n            <td>{{ order.totals.paid }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.totals.products</td>\r\n            <td>{{ order.totals.products }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.totals.shipping</td>\r\n            <td>{{ order.totals.shipping }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.totals.discounts</td>\r\n            <td>{{ order.totals.discounts }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.totals.tax</td>\r\n            <td>{{ order.totals.tax }}</td>\r\n          </tr>\r\n        </tbody>\r\n      </table>\r\n    </div>\r\n\r\n    <div class=\"section\">\r\n      <h2>Dirección de facturación</h2>\r\n\r\n      <table>\r\n        <thead>\r\n          <tr>\r\n            <th>Nombre de la variable</th>\r\n            <th>Variable Twig</th>\r\n          </tr>\r\n        </thead>\r\n        <tbody>\r\n          <tr>\r\n            <td>order.billing_address.firstname</td>\r\n            <td>{{ order.billing_address.firstname }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.billing_address.lastname</td>\r\n            <td>{{ order.billing_address.lastname }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.billing_address.full_name</td>\r\n            <td>{{ order.billing_address.full_name }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.billing_address.company</td>\r\n            <td>{{ order.billing_address.company }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.billing_address.address1</td>\r\n            <td>{{ order.billing_address.address1 }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.billing_address.address2</td>\r\n            <td>{{ order.billing_address.address2 }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.billing_address.city</td>\r\n            <td>{{ order.billing_address.city }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.billing_address.postcode</td>\r\n            <td>{{ order.billing_address.postcode }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.billing_address.country</td>\r\n            <td>{{ order.billing_address.country }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.billing_address.state</td>\r\n            <td>{{ order.billing_address.state }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.billing_address.phone</td>\r\n            <td>{{ order.billing_address.phone }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.billing_address.phone_mobile</td>\r\n            <td>{{ order.billing_address.phone_mobile }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.billing_address.formatted</td>\r\n            <td>{{ order.billing_address.formatted|nl2br }}</td>\r\n          </tr>\r\n        </tbody>\r\n      </table>\r\n    </div>\r\n\r\n    <div class=\"section\">\r\n      <h2>Dirección de envío</h2>\r\n\r\n      <table>\r\n        <thead>\r\n          <tr>\r\n            <th>Nombre de la variable</th>\r\n            <th>Variable Twig</th>\r\n          </tr>\r\n        </thead>\r\n        <tbody>\r\n          <tr>\r\n            <td>order.shipping_address.firstname</td>\r\n            <td>{{ order.shipping_address.firstname }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.shipping_address.lastname</td>\r\n            <td>{{ order.shipping_address.lastname }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.shipping_address.full_name</td>\r\n            <td>{{ order.shipping_address.full_name }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.shipping_address.company</td>\r\n            <td>{{ order.shipping_address.company }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.shipping_address.address1</td>\r\n            <td>{{ order.shipping_address.address1 }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.shipping_address.address2</td>\r\n            <td>{{ order.shipping_address.address2 }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.shipping_address.city</td>\r\n            <td>{{ order.shipping_address.city }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.shipping_address.postcode</td>\r\n            <td>{{ order.shipping_address.postcode }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.shipping_address.country</td>\r\n            <td>{{ order.shipping_address.country }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.shipping_address.state</td>\r\n            <td>{{ order.shipping_address.state }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.shipping_address.phone</td>\r\n            <td>{{ order.shipping_address.phone }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.shipping_address.phone_mobile</td>\r\n            <td>{{ order.shipping_address.phone_mobile }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.shipping_address.formatted</td>\r\n            <td>{{ order.shipping_address.formatted|nl2br }}</td>\r\n          </tr>\r\n        </tbody>\r\n      </table>\r\n    </div>\r\n\r\n    <div class=\"section\">\r\n      <h2>Envío</h2>\r\n\r\n      <table>\r\n        <thead>\r\n          <tr>\r\n            <th>Nombre de la variable</th>\r\n            <th>Variable Twig</th>\r\n          </tr>\r\n        </thead>\r\n        <tbody>\r\n          <tr>\r\n            <td>order.shipping.carrier_name</td>\r\n            <td>{{ order.shipping.carrier_name }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.shipping.cost</td>\r\n            <td>{{ order.shipping.cost }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.shipping.tracking_url</td>\r\n            <td>{{ order.shipping.tracking_url }}</td>\r\n          </tr>\r\n        </tbody>\r\n      </table>\r\n    </div>\r\n\r\n    <div class=\"section\">\r\n      <h2>Productos del pedido</h2>\r\n\r\n      <table>\r\n        <thead>\r\n          <tr>\r\n            <th>Nombre de la variable</th>\r\n            <th>Variable Twig</th>\r\n          </tr>\r\n        </thead>\r\n        <tbody>\r\n\r\n          <tr class=\"loop-title\">\r\n            <td colspan=\"2\">\r\n              Inicio de bucle de order.products<br>\r\n              <code>{% for product in order.products %}</code>\r\n            </td>\r\n          </tr>\r\n\r\n          {% for product in order.products %}\r\n\r\n          <tr>\r\n            <td>order.products[].id</td>\r\n            <td>{{ product.id }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.products[].attribute_id</td>\r\n            <td>{{ product.attribute_id }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.products[].name</td>\r\n            <td>{{ product.name }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.products[].reference</td>\r\n            <td>{{ product.reference }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.products[].quantity</td>\r\n            <td>{{ product.quantity }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.products[].unit_price</td>\r\n            <td>{{ product.unit_price }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.products[].total_price</td>\r\n            <td>{{ product.total_price }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.products[].unit_price_tax_excl</td>\r\n            <td>{{ product.unit_price_tax_excl }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.products[].unit_price_tax_incl</td>\r\n            <td>{{ product.unit_price_tax_incl }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.products[].total_price_tax_excl</td>\r\n            <td>{{ product.total_price_tax_excl }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.products[].total_price_tax_incl</td>\r\n            <td>{{ product.total_price_tax_incl }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.products[].url</td>\r\n            <td>{{ product.url }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.products[].image_url</td>\r\n            <td>{{ product.image_url }}</td>\r\n          </tr>\r\n\r\n          <tr class=\"loop-title\">\r\n            <td colspan=\"2\">\r\n              Inicio de bucle de order.products[].attributes<br>\r\n              <code>{% for product_attribute in product.attributes %}</code>\r\n            </td>\r\n          </tr>\r\n\r\n          {% for product_attribute in product.attributes %}\r\n\r\n          <tr>\r\n            <td>order.products[].attributes[].label</td>\r\n            <td>{{ product_attribute.label }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>order.products[].attributes[].value</td>\r\n            <td>{{ product_attribute.value }}</td>\r\n          </tr>\r\n\r\n          {% endfor %}\r\n\r\n          <tr class=\"loop-title\">\r\n            <td colspan=\"2\">\r\n              Fin de bucle de order.products[].attributes<br>\r\n              <code>{% endfor %}</code>\r\n            </td>\r\n          </tr>\r\n\r\n          {% endfor %}\r\n\r\n          <tr class=\"loop-title\">\r\n            <td colspan=\"2\">\r\n              Fin de bucle de order.products<br>\r\n              <code>{% endfor %}</code>\r\n            </td>\r\n          </tr>\r\n\r\n        </tbody>\r\n      </table>\r\n    </div>\r\n\r\n    <div class=\"section\">\r\n      <h2>Productos relacionados</h2>\r\n\r\n      <table>\r\n        <thead>\r\n          <tr>\r\n            <th>Nombre de la variable</th>\r\n            <th>Variable Twig</th>\r\n          </tr>\r\n        </thead>\r\n        <tbody>\r\n\r\n          <tr class=\"loop-title\">\r\n            <td colspan=\"2\">\r\n              Inicio de bucle de related_products<br>\r\n              <code>{% for related_product in related_products %}</code>\r\n            </td>\r\n          </tr>\r\n\r\n          {% for related_product in related_products %}\r\n\r\n          <tr>\r\n            <td>related_products[].id</td>\r\n            <td>{{ related_product.id }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>related_products[].name</td>\r\n            <td>{{ related_product.name }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>related_products[].price</td>\r\n            <td>{{ related_product.price }}</td>\r\n          </tr>\r\n          <tr>\r\n            <td>related_products[].url</td>\r\n            <td>{{ related_product.url }}</td>\r\n          </tr>\r\n          <tr>\r\n        