(3, 1, 1, 'order_status_changed_shipped', 'order', 'Post-compra 02 - Seguimiento de envío', 'Tu pedido {{ order.reference }} está en camino', 'mailsendvx_default', '<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\">\r\n  <tr>\r\n    <td style=\"padding:40px 40px 0 40px;\">\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\">\r\n        <tr>\r\n          <td style=\"background-color:#E8EDF2; border-radius:20px; padding:5px 12px;\">\r\n            <span style=\"font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">En camino</span>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:16px 40px 0 40px; font-family:Arial, Helvetica, sans-serif; font-size:26px; font-weight:bold; line-height:34px; color:#201E1A;\">\r\n      {{ customer.firstname|default(customer.name) }}, tu pedido salió.\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:12px 40px 0 40px; font-family:Arial, Helvetica, sans-serif; font-size:15px; line-height:24px; color:#6E6A62;\">\r\n      Ya está en camino. Aquí tienes los datos de tu envío para darle seguimiento.\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:24px 40px 0 40px;\">\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background-color:#FDF3E7; border:1px solid #FAD5A0; border-radius:14px;\">\r\n        <tr>\r\n          <td style=\"padding:24px;\">\r\n            <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\">\r\n              <tr>\r\n                <td valign=\"top\">\r\n                  <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:10px; font-weight:bold; color:#8A4508;\">PEDIDO EN CAMINO</span>\r\n                  <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:20px; font-weight:bold; color:#C4690A; padding-top:6px;\"