     <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"border-bottom:1px solid #E6E1D8;\">\r\n        <tr>\r\n          <td width=\"58\" valign=\"top\" style=\"padding:16px 0;\">\r\n            <table role=\"presentation\" width=\"50\" height=\"50\" cellpadding=\"0\" cellspacing=\"0\" style=\"background-color:#F6F4F0; border:1px solid #E6E1D8; border-radius:8px;\">\r\n              <tr><td>\r\n                {% if item.image_url %}<img src=\"{{ item.image_url }}\" width=\"50\" height=\"50\" alt=\"{{ item.name }}\" style=\"display:block; border-radius:8px;\">{% endif %}\r\n              </td></tr>\r\n            </table>\r\n          </td>\r\n          <td valign=\"top\" style=\"padding:16px 12px;\">\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:13px; font-weight:bold; color:#201E1A;\">{{ item.name }}</span>\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:11px; color:#6E6A62; padding-top:4px;\">Cantidad: {{ item.quantity }}</span>\r\n          </td>\r\n          <td valign=\"top\" align=\"right\" style=\"padding:16px 0;\">\r\n            <span style=\"font-family:Arial, Helvetica, sans-serif; font-size:12px; font-weight:bold; color:#201E1A;\">${{ item.total_price }}</span>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n      {% endfor %}\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\">\r\n        <tr>\r\n          <td style=\"padding:14px 0; font-family:Arial, Helvetica, sans-serif; font-size:15px; font-weight:bold; color:#201E1A;\">Total enviado</td>\r\n          <td align=\"right\" style=\"padding:14px 0; font-family:Arial, Helvetica, sans-serif; font-size:15px; font-weight:bold; color:#201E1A;\">${{ order.totals.paid }}</td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td align=\"center\" style=\"padding:28px 40px 40px 40px; font-family:Arial, Helvetica, sans-serif; font-size:13px; color:#6E6A62;\">\r\n      ¿Preguntas sobre tu envío?\r\n      <a href=\"{{ shop.url }}\" style=\"color:#1B3A5C; font-weight:bold; text-decoration:none;\">Escríbenos con tu número de pedido →</a>\r\n    </td>\r\n  </tr>\r\n</table>', 'En camino\n{{ customer.firstname|default(customer.name) }}, tu pedido salió.\nYa está en camino. Aquí tienes los datos de tu envío para darle seguimiento.\nPEDIDO EN CAMINO\n{{ order.reference }}\nTransportista: {{ order.shipping.carrier_name }}\n{% if order.shipping.tracking_url %}\nVer estado de mi pedido\n{% else %}\nVer estado de mi pedido\n{% endif %}\nESTADO ACTUAL\n{{ order.status }}\n✓\n✓\n●\n●\nConfirmado\nDespachado\nEn tránsito\nEntregado\nPedido {{ order.reference }}\n{% for item in order.products %}\n{% if item.image_url %}{% endif %}\n{{ item.name }}\nCantidad: {{ item.quantity }}\n${{ item.total_price }}\n{% endfor %}\nTotal enviado\n${{ order.totals.paid }}\n¿Preguntas sobre tu envío?\nEscríbenos con tu número de pedido →', NULL, 'prestashop_mail', 1, '2026-07-01 17:15:58', '2026-07-07 16:44:23'),
(4, 1, 1, 'order_created', 'order', 'Post-compra 01 - Confirmación de pedido', '¡Gracias por tu pedido {{ order.reference }}, {{ customer.firstname }}!', 'mailsendvx_default', '<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\">\r\n  <tr>\r\n    <td style=\"padding:40px 40px 0 40px;\">\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\">\r\n        <tr>\r\n          <td style=\"background-color:#E8EDF2; border-radius:20px; padding:5px 12px;\">\r\n            <span style=\"font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">Pedido confirmado</span>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:16px 40px 0 40px; font-family:Arial, Helvetica, sans-serif; font-size:26px; font-weight:bold; line-height:34px; color:#201E1A;\">\r\n      ¡Gracias, {{ customer.firstname|default(customer.name) }}! Tu pedido está listo.\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:12px 40px 0 40px; font-family:Arial, Helvetica, sans-serif; font-size:15px; line-height:24px; color:#6E6A62;\">\r\n      Lo estamos procesando. Te notificaremos cuando salga a despacho.\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:24px 40px 0 40px;\">\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background-color:#F6F4F0; border-radius:12px;\">\r\n        <tr>\r\n          <td style=\"padding:20px 24px; font-family:Arial, Helvetica, sans-serif;\">\r\n            <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\">\r\n              <tr>\r\n                <td valign=\"top\">\r\n                  <span style=\"display:block; font-size:10px; font-weight:bold; color:#6E6A62;\">NÚMERO DE PEDIDO</span>\r\n                  <span style=\"display:block; font-size:16px; font-weight:bold; color:#1B3A5C; padding-top:4px;\">{{ order.reference }}</span>\r\n                </td>\r\n                <td valign=\"top\" align=\"right\">\r\n                  <span style=\"display:block; font-size:10px; font-weight:bold; color:#6E6A62;\">FECHA</span>\r\n                  <span style=\"display:block; font-size:12px; font-weight:bold; color:#201E1A; padding-top:4px;\">{{ order.formated_date }}</span>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:24px 40px 0 40px;\">\r\n      {% for item in order.products %}\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"border-bottom:1px solid #E6E1D8;\">\r\n        <tr>\r\n          <td width=\"58\" valign=\"top\" style=\"padding:16px 0;\">\r\n            <table role=\"presentation\" width=\"50\" height=\"50\" cellpadding=\"0\" cellspacing=\"0\" style=\"background-color:#F6F4F0; border:1px solid #E6E1D8; border-radius:8px;\">\r\n              <tr><td>\r\n                {% if item.image_url %}<img src=\"{{ item.image_url }}\" width=\"50\" height=\"50\" alt=\"{{ item.name }}\" style=\"display:block; border-radius:8px;\">{% endif %}\r\n              </td></tr>\r\n            </table>\r\n          </td>\r\n          <td valign=\"top\" style=\"padding:16px 12px;\">\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:13px; font-weight:bold; color:#201E1A;\">{{ item.name }}</span>\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:11px; color:#6E6A62; padding-top:4px;\">Cantidad: {{ item.quantity }}</span>\r\n          </td>\r\n          <td valign=\"top\" align=\"right\" style=\"padding:16px 0;\">\r\n            <span style=\"font-family:Arial, Helvetica, sans-serif; font-size:12px; font-weight:bold; color:#201E1A;\">${{ item.total_price }}</span>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n      {% endfor %}\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\">\r\n        <tr>\r\n          <td style=\"padding:12px 0; font-family:Arial, Helvetica, sans-serif; font-size:12px; color:#6E6A62;\">Subtotal</td>\r\n          <td align=\"right\" style=\"padding:12px 0; font-family:Arial, Helvetica, sans-serif; font-size:12px; color:#6E6A62;\">${{ order.totals.products }}</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding:0 0 12px 0; font-family:Arial, Helvetica, sans-serif; font-size:12px; color:#6E6A62;\">Envío</td>\r\n          <td align=\"right\" style=\"padding:0 0 12px 0; font-family:Arial, Helvetica, sans-serif; font-size:12px; color:#6E6A62;\">${{ order.totals.shipping }}</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding:12px 0; border-top:1px solid #E6E1D8; font-family:Arial, Helvetica, sans-serif; font-size:15px; font-weight:bold; color:#201E1A;\">Total pagado</td>\r\n          <td align=\"right\" style=\"padding:12px 0; border-top:1px solid #E6E1D8; font-family:Arial, Helvetica, sans-serif; font-size:15px; font-weight:bold; color:#201E1A;\">${{ order.totals.paid }}</td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:24px 40px 0 40px;\">\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\">\r\n        <tr>\r\n          <td width=\"48%\" valign=\"top\" style=\"background-color:#F6F4F0; border-radius:12px; padding:20px;\">\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:10px; font-weight:bold; color:#6E6A62;\">DIRECCIÓN DE ENTREGA</span>\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:13px; font-weight:bold; color:#201E1A; padding-top:8px;\">{{ order.shipping_address.full_name }}</span>\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:12px; color:#6E6A62; padding-top:6px; line-height:18px;\">{{ order.shipping_address.address1 }}<br>{{ order.shipping_address.city }}, {{ order.shipping_address.country }}</span>\r\n          </td>\r\n          <td width=\"4%\"> </td>\r\n          <td width=\"48%\" valign=\"top\" style=\"background-color:#F6F4F0; border-radius:12px; padding:20px;\">\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:10px; font-weight:bold; color:#6E6A62;\">MÉTODO DE PAGO</span>\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:13px; font-weight:bold; color:#201E1A; padding-top:8px;\">{{ order.payment_method }}</span>\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:12px; color:#6E6A62; padding-top:6px;\">Entrega vía: {{ order.shipping_method }}</span>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n  {% if \'transferencia\' in order.payment_method|lower %}\r\n  <tr>\r\n    <td style=\"padding:24px 40px 0 40px;\">\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background-color:#FDF3E7; border:1px solid #FAD5A0; border-radius:12px;\">\r\n        <tr>\r\n          <td style=\"padding:24px; font-family:Arial, Helvetica, sans-serif;\">\r\n            <span style=\"display:block; font-size:13px; font-weight:bold; color:#8A4508;\">Si tu pago fue por transferencia bancaria</span>\r\n            <span style=\"display:block; font-size:12px; color:#8A4508; padding-top:10px; line-height:20px;\">Envía tu comprobante por WhatsApp para activar el pedido más rápido:</span>\r\n            <span style=\"display:block; font-size:12px; color:#8A4508; padding-top:14px; line-height:21px;\">\r\n              <strong>Razón social:</strong> {{ shop.name }} · ID fiscal 1234567890001<br>\r\n              <strong>Banco A:</strong> 2200145789 · <strong>Banco B:</strong> 3300987654\r\n            </span>\r\n            <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:18px;\">\r\n              <tr>\r\n                <td style=\"background-color:#25D366; border-radius:8px; padding:12px 20px;\">\r\n                  <a href=\"#\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:13px; font-weight:bold; color:#FFFFFF; text-decoration:none;\">Enviar comprobante por WhatsApp</a>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n  {% endif %}\r\n  <tr>\r\n    <td style=\"padding:32px 40px 0 40px;\">\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\">\r\n        <tr>\r\n          <td style=\"background-color:#E8EDF2; border-radius:20px; padding:5px 12px;\">\r\n            <span style=\"font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">¿Qué sigue ahora?</span>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:20px 40px 0 40px;\">\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\">\r\n        <tr>\r\n          <td width=\"30\" valign=\"top\" style=\"padding:0 12px 20px 0;\">\r\n            <table role=\"presentation\" width=\"26\" height=\"26\" cellpadding=\"0\" cellspacing=\"0\" style=\"background-color:#1B3A5C; border-radius:13px;\">\r\n              <tr><td align=\"center\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#FFFFFF;\">1</td></tr>\r\n            </table>\r\n          </td>\r\n          <td valign=\"top\" style=\"padding:0 0 20px 0;\">\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:13px; font-weight:bold; color:#201E1A;\">Procesamos tu pedido</span>\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:12px; color:#6E6A62; padding-top:4px; line-height:19px;\">Nuestro equipo verifica stock y prepara tu despacho.</span>\r\n          </td>\r\n        </tr>\r\n        <tr>\r\n          <td width=\"30\" valign=\"top\" style=\"padding:0 12px 20px 0;\">\r\n            <table role=\"presentation\" width=\"26\" height=\"26\" cellpadding=\"0\" cellspacing=\"0\" style=\"background-color:#F6F4F0; border:1px solid #E6E1D8; border-radius:13px;\">\r\n              <tr><td align=\"center\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">2</td></tr>\r\n            </table>\r\n          </td>\r\n          <td valign=\"top\" style=\"padding:0 0 20px 0;\">\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:13px; font-weight:bold; color:#201E1A;\">Te notificamos el despacho</span>\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:12px; color:#6E6A62; padding-top:4px; line-height:19px;\">Recibirás un email con el número de guía para que puedas rastrear tu envío.</span>\r\n          </td>\r\n        </tr>\r\n        <tr>\r\n          <td width=\"30\" valign=\"top\" style=\"padding:0 12px 0 0;\">\r\n            <table role=\"presentation\" width=\"26\" height=\"26\" cellpadding=\"0\" cellspacing=\"0\" style=\"background-color:#F6F4F0; border:1px solid #E6E1D8; border-radius:13px;\">\r\n              <tr><td align=\"center\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">3</td></tr>\r\n            </table>\r\n          </td>\r\n          <td valign=\"top\">\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:13px; font-weight:bold; color:#201E1A;\">Recibes tu pedido</span>\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:12px; color:#6E6A62; padding-top:4px; line-height:19px;\">En los tiempos estimados según tu ubicación. Si tu comercio ofrece retiro en tienda, también puedes elegir esa opción.</span>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td align=\"center\" style=\"padding:32px 40px 40px 40px; font-family:Arial, Helvetica, sans-serif; font-size:13px; color:#6E6A62;\">\r\n      ¿Preguntas sobre tu pedido?\r\n      <a href=\"{{ shop.url }}\" style=\"color:#1B3A5C; font-weight:bold; text-decoration:none;\">Escríbenos con tu número de pedido →</a>\r\n    </td>\r\n  </tr>\r\n</table>', 'Pedido confirmado\n¡Gracias, {{ customer.firstname|default(customer.name) }}! Tu pedido está listo.\nLo estamos procesando. Te notificaremos cuando salga a despacho.\nNÚMERO DE PEDIDO\n{{ order.reference }}\nFECHA\n{{ order.formated_date }}\n{% for item in order.products %}\n{% if item.image_url %}{% endif %}\n{{ item.name }}\nCantidad: {{ item.quantity }}\n${{ item.total_price }}\n{% endfor %}\nSubtotal\n${{ order.totals.products }}\nEnvío\n${{ order.totals.shipping }}\nTotal pagado\n${{ order.totals.paid }}\nDIRECCIÓN DE ENTREGA\n{{ order.shipping_address.full_name }}\n{{ order.shipping_address.address1 }}\n{{ order.shipping_address.city }}, {{ order.shipping_address.country }}\nMÉTODO DE PAGO\n{{ order.payment_method }}\nEntrega vía: {{ order.shipping_method }}\n{% if \'transferencia\' in order.payment_method|lower %}\nSi tu pago fue por transferencia bancaria\nEnvía tu comprobante por WhatsApp para activar el pedido más rápido:\nRazón social: {{ shop.name }} · ID fiscal 1234567890001\nBanco A: 2200145789 · Banco B: 3300987654\nEnviar comprobante por WhatsApp\n{% endif %}\n¿Qué sigue ahora?\n1\nProcesamos tu pedido\nNuestro equipo verifica stock y prepara tu despacho.\n2\nTe notificamos el despacho\nRecibirás un email con el número de guía para que puedas rastrear tu envío.\n3\nRecibes tu pedido\nEn los tiempos estimados según tu ubicación. Si tu comercio ofrece retiro en tienda, también puedes elegir esa opción.\n¿Preguntas sobre tu pedido?\nEscríbenos con tu número de pedido →', NULL, 'prestashop_mail', 1, '2026-07-02 15:51:15', '2026-07-07 16:20:39');
INSERT INTO `ps_mailsendvx_template` (`id_mailsendvx_template`, `id_shop`, `id_lang`, `event_name`, `context_type`, `name`, `subject`, `mail_template`, `html_content`, `text_content`, `json_design`, `provider`, `active`, `date_add`, `date_upd`) VALUES
(5, 1, 1, NULL, 'order', 'Post-compra 03 - Reseña', '{{ customer.firstname }}, ¿cómo te fue con tu pedido {{ order.reference }}?', 'mailsendvx_default', '<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\">\r\n  <tr>\r\n    <td style=\"padding:40px 40px 0 40px;\">\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\">\r\n        <tr>\r\n          <td style=\"background-color:#E8EDF2; border-radius:20px; padding:5px 12px;\">\r\n            <span style=\"font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">Cuéntanos tu experiencia</span>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:16px 40px 0 40px; font-family:Arial, Helvetica, sans-serif; font-size:26px; font-weight:bold; line-height:34px; color:#201E1A;\">\r\n      {{ customer.firstname|default(customer.name) }}, ¿cómo te fue con tus productos?\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:12px 40px 0 40px; font-family:Arial, Helvetica, sans-serif; font-size:15px; line-height:24px; color:#6E6A62;\">\r\n      Tu opinión ayuda a otras personas a tomar mejores decisiones. Y nosotros mejoramos con cada comentario.\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:24px 40px 0 40px;\">\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background-color:#1B3A5C; border-radius:14px;\">\r\n        <tr>\r\n          <td style=\"padding:28px;\">\r\n            <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\">\r\n              <tr>\r\n                <td style=\"background-color:#33506F; border-radius:20px; padding:5px 12px;\">\r\n                  <span style=\"font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#FFFFFF;\">Por tu opinión</span>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n            <div style=\"height:14px; line-height:14px; font-size:0;\"> </div>\r\n            <span style=\"font-family:Arial, Helvetica, sans-serif; font-size:24px; font-weight:bold; color:#FFFFFF;\">10% off</span>\r\n            <div style=\"height:8px; line-height:8px; font-size:0;\"> </div>\r\n            <span style=\"font-family:Arial, Helvetica, sans-serif; font-size:12px; color:#B9C6D4;\">En tu próxima compra · Sin monto mínimo · Válido 30 días desde la reseña</span>\r\n            <div style=\"height:16px; line-height:16px; font-size:0;\"> </div>\r\n            <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\">\r\n              <tr>\r\n                <td style=\"background-color:#33506F; border:1px solid #55708C; border-radius:8px; padding:10px 22px;\">\r\n                  <span style=\"font-family:Arial, Helvetica, sans-serif; font-size:15px; font-weight:bold; color:#FFFFFF;\">OPINION10</span>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:32px 40px 0 40px;\">\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\">\r\n        <tr>\r\n          <td style=\"background-color:#E8EDF2; border-radius:20px; padding:5px 12px;\">\r\n            <span style=\"font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">Califica tu pedido</span>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n  {% for item in order.products|slice(0, 3) %}\r\n  <tr>\r\n    <td style=\"padding:16px 40px 0 40px;\">\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"border:1px solid #E6E1D8; border-radius:14px;\">\r\n        <tr>\r\n          <td style=\"padding:22px;\">\r\n            <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\">\r\n              <tr>\r\n                <td width=\"62\" valign=\"top\">\r\n                  <table role=\"presentation\" width=\"54\" height=\"54\" cellpadding=\"0\" cellspacing=\"0\" style=\"background-color:#F6F4F0; border:1px solid #E6E1D8; border-radius:10px;\">\r\n                    <tr><td>\r\n                      {% if item.image_url %}<img src=\"{{ item.image_url }}\" width=\"54\" height=\"54\" alt=\"{{ item.name }}\" style=\"display:block; border-radius:10px;\">{% endif %}\r\n                    </td></tr>\r\n                  </table>\r\n                </td>\r\n                <td valign=\"middle\" style=\"padding-left:14px;\">\r\n                  <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:14px; font-weight:bold; color:#201E1A;\">{{ item.name }}</span>\r\n                  <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:11px; color:#6E6A62; padding-top:4px;\">Cantidad: {{ item.quantity }}</span>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n            <div style=\"height:16px; line-height:16px; font-size:0;\"> </div>\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:11px; color:#6E6A62;\">¿Cómo calificarías este producto?</span>\r\n            <div style=\"height:8px; line-height:8px; font-size:0;\"> </div>\r\n            <span style=\"font-family:Arial, Helvetica, sans-serif; font-size:18px; color:#C4690A; letter-spacing:4px;\">★★★★★</span>\r\n            <div style=\"height:16px; line-height:16px; font-size:0;\"> </div>\r\n            <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\">\r\n              <tr>\r\n                <td style=\"background-color:#1B3A5C; border-radius:8px; padding:10px 20px;\">\r\n                  <a href=\"{{ item.url }}\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:12px; font-weight:bold; color:#FFFFFF; text-decoration:none;\">Dejar mi reseña →</a>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n  {% endfor %}\r\n\r\n  <!-- Ver el resto — solo si el pedido tiene más de 3 productos -->\r\n  {% if order.products|length > 3 %}\r\n  <tr>\r\n    <td align=\"center\" style=\"padding:20px 40px 0 40px;\">\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\">\r\n        <tr>\r\n          <td style=\"border:1px solid #E6E1D8; border-radius:8px; padding:11px 24px;\">\r\n            <a href=\"{{ shop.url }}\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:13px; font-weight:bold; color:#1B3A5C; text-decoration:none;\">Calificar todos los productos →</a>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n  {% endif %}\r\n  <tr>\r\n    <td style=\"padding:32px 40px 0 40px;\">\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background-color:#FDF3E7; border-left:3px solid #C4690A; border-radius:0 10px 10px 0;\">\r\n        <tr>\r\n          <td style=\"padding:22px 25px;\">\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:13px; font-weight:bold; color:#8A4508;\">¿Tuviste algún inconveniente?</span>\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:12px; color:#8A4508; padding-top:8px; line-height:20px;\">Antes de calificar, cuéntanos. Queremos resolver cualquier problema contigo directamente.</span>\r\n            <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" style=\"margin-top:16px;\">\r\n              <tr>\r\n                <td style=\"border:1px solid #FAD5A0; border-radius:8px; padding:10px 22px;\">\r\n                  <a href=\"{{ shop.url }}\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:12px; font-weight:bold; color:#C4690A; text-decoration:none;\">Contactar soporte →</a>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td align=\"center\" style=\"padding:32px 40px 40px 40px; font-family:Arial, Helvetica, sans-serif; font-size:13px; color:#6E6A62;\">\r\n      Gracias por comprar en {{ shop.name }}.\r\n    </td>\r\n  </tr>\r\n</table>', 'Cuéntanos tu experiencia\n{{ customer.firstname|default(customer.name) }}, ¿cómo te fue con tus productos?\nTu opinión ayuda a otras personas a tomar mejores decisiones. Y nosotros mejoramos con cada comentario.\nPor tu opinión\n10% off\nEn tu próxima compra · Sin monto mínimo · Válido 30 días desde la reseña\nOPINION10\nCalifica tu pedido\n{% for item in order.products|slice(0, 3) %}\n{% if item.image_url %}{% endif %}\n{{ item.name }}\nCantidad: {{ item.quantity }}\n¿Cómo calificarías este producto?\n★★★★★\nDejar mi reseña →\n{% endfor %}\n{% if order.products|length > 3 %}\nCalificar todos los productos →\n{% endif %}\n¿Tuviste algún inconveniente?\nAntes de calificar, cuéntanos. Queremos resolver cualquier problema contigo directamente.\nContactar soporte →\nGracias por comprar en {{ shop.name }}.', NULL, 'prestashop_mail', 1, '2026-07-02 21:54:20', '2026-07-08 12:36:22'),
(6, 1, 1, NULL, 'newsletter', 'Suscripción 01 - Bienvenida', '¡Bienvenido/a a {{ shop.name }}, {{ customer.firstname }}!', 'mailsendvx_default', '<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\">\r\n  <!-- Badge + título -->\r\n  <tr>\r\n    <td style=\"padding:40px 40px 0 40px;\">\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\">\r\n        <tr>\r\n          <td style=\"background-color:#E8EDF2; border-radius:20px; padding:5px 12px;\">\r\n            <span style=\"font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">Bienvenida</span>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:16px 40px 0 40px; font-family:Arial, Helvetica, sans-serif; font-size:28px; font-weight:bold; line-height:36px; color:#201E1A;\">\r\n      Hola, {{ customer.firstname ?: customer.name }}. Bienvenido/a a {{ shop.name }}.\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:16px 40px 0 40px; font-family:Arial, Helvetica, sans-serif; font-size:15px; line-height:24px; color:#6E6A62;\">\r\n      Nos alegra tenerte aquí. A partir de ahora vas a encontrar todo lo que necesitas en un solo lugar, con la atención que mereces.\r\n    </td>\r\n  </tr>\r\n\r\n  <!-- Oferta de bienvenida -->\r\n  <tr>\r\n    <td style=\"padding:32px 40px 0 40px;\">\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background-color:#F5F7FA; border:1px solid #DCE3EA; border-radius:12px;\">\r\n        <tr>\r\n          <td style=\"padding:24px;\">\r\n            <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\">\r\n              <tr>\r\n                <td style=\"background-color:#E8EDF2; border-radius:20px; padding:5px 12px;\">\r\n                  <span style=\"font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">Oferta de bienvenida</span>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n            <div style=\"height:12px; line-height:12px; font-size:0;\"> </div>\r\n            <span style=\"font-family:Arial, Helvetica, sans-serif; font-size:26px; font-weight:bold; color:#201E1A;\">10% en tu primera compra</span>\r\n            <div style=\"height:8px; line-height:8px; font-size:0;\"> </div>\r\n            <span style=\"font-family:Arial, Helvetica, sans-serif; font-size:14px; color:#6E6A62;\">+ envío gratis en tu primer pedido</span>\r\n            <div style=\"height:16px; line-height:16px; font-size:0;\"> </div>\r\n            <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\">\r\n              <tr>\r\n                <td style=\"background-color:#FFFFFF; border:1px solid #B7C4D1; border-radius:8px; padding:10px 20px;\">\r\n                  <span style=\"font-family:Arial, Helvetica, sans-serif; font-size:16px; font-weight:bold; color:#1B3A5C;\">BIENVENIDO10</span>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n            <div style=\"height:14px; line-height:14px; font-size:0;\"> </div>\r\n            <span style=\"font-family:Arial, Helvetica, sans-serif; font-size:12px; color:#6E6A62;\">Válido por 7 días · Sin monto mínimo · Solo primera compra</span>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n\r\n  <!-- Stats -->\r\n  <tr>\r\n    <td style=\"padding:32px 40px 0 40px;\">\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\">\r\n        <tr>\r\n          <td style=\"background-color:#E8EDF2; border-radius:20px; padding:5px 12px;\">\r\n            <span style=\"font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">Por qué elegir {{ shop.name }}</span>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n  <tr>\r\n    <td style=\"padding:16px 40px 0 40px;\">\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\">\r\n        <tr>\r\n          <td width=\"32%\" align=\"center\" style=\"background-color:#F6F4F0; border:1px solid #E6E1D8; border-radius:10px; padding:16px 8px;\">\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:20px; font-weight:bold; color:#201E1A;\">30+</span>\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:11px; color:#6E6A62; padding-top:4px;\">Años en el mercado</span>\r\n          </td>\r\n          <td width=\"2%\"> </td>\r\n          <td width=\"32%\" align=\"center\" style=\"background-color:#F6F4F0; border:1px solid #E6E1D8; border-radius:10px; padding:16px 8px;\">\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:20px; font-weight:bold; color:#201E1A;\">10K+</span>\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:11px; color:#6E6A62; padding-top:4px;\">Clientes satisfechos</span>\r\n          </td>\r\n          <td width=\"2%\"> </td>\r\n          <td width=\"32%\" align=\"center\" style=\"background-color:#F6F4F0; border:1px solid #E6E1D8; border-radius:10px; padding:16px 8px;\">\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:20px; font-weight:bold; color:#201E1A;\">24h</span>\r\n            <span style=\"display:block; font-family:Arial, Helvetica, sans-serif; font-size:11px; color:#6E6A62; padding-top:4px;\">Tiempo de respuesta</span>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n\r\n  <!-- CTA -->\r\n  <tr>\r\n    <td style=\"padding:32px 0 0 0;\">\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"background-color:#F6F4F0;\">\r\n        <tr>\r\n          <td align=\"center\" style=\"padding:28px 40px 0 40px;\">\r\n            <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\">\r\n              <tr>\r\n                <td style=\"background-color:#1B3A5C; border-radius:8px; padding:14px 28px;\">\r\n                  <a href=\"{{ shop.url }}\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:14px; font-weight:bold; color:#FFFFFF; text-decoration:none;\">Explorar catálogo →</a>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n        </tr>\r\n        <tr>\r\n          <td align=\"center\" style=\"padding:16px 40px 28px 40px; font-family:Arial, Helvetica, sans-serif; font-size:13px; color:#6E6A62;\">\r\n            ¿Tienes dudas?\r\n            <a href=\"mailto:hola@tutienda.com\" style=\"color:#1B3A5C; font-weight:bold; text-decoration:none;\">Escríbenos →</a>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n\r\n  <!-- Categorías -->\r\n  <tr>\r\n    <td style=\"padding:32px 40px 40px 40px;\">\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\">\r\n        <tr>\r\n          <td style=\"background-color:#E8EDF2; border-radius:20px; padding:5px 12px;\">\r\n            <span style=\"font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">Explora por categoría</span>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n      <div style=\"height:16px; line-height:16px; font-size:0;\"> </div>\r\n      <a href=\"{{ shop.url }}\" style=\"display:inline-block; font-family:Arial, Helvetica, sans-serif; font-size:12px; font-weight:500; color:#1B3A5C; background-color:#F5F7FA; border:1px solid #C7D3DE; border-radius:20px; padding:8px 16px; text-decoration:none; margin:0 8px 8px 0;\">Novedades</a>\r\n      <a href=\"{{ shop.url }}\" style=\"display:inline-block; font-family:Arial, Helvetica, sans-serif; font-size:12px; font-weight:500; color:#1B3A5C; background-color:#F5F7FA; border:1px solid #C7D3DE; border-radius:20px; padding:8px 16px; text-decoration:none; margin:0 8px 8px 0;\">Más vendidos</a>\r\n      <a href=\"{{ shop.url }}\" style=\"display:inline-block; font-family:Arial, Helvetica, sans-serif; font-size:12px; font-weight:500; color:#1B3A5C; background-color:#F5F7FA; border:1px solid #C7D3DE; border-radius:20px; padding:8px 16px; text-decoration:none; margin:0 8px 8px 0;\">Ofertas</a>\r\n      <a href=\"{{ shop.url }}\" style=\"display:inline-block; font-family:Arial, Helvetica, sans-serif; font-size:12px; font-weight:500; color:#1B3A5C; background-color:#F5F7FA; border:1px solid #C7D3DE; border-radius:20px; padding:8px 16px; text-decoration:none; margin:0 8px 8px 0;\">Accesorios</a>\r\n    </td>\r\n  </tr>\r\n</table>', 'Bienvenida\nHola, {{ customer.firstname ?: customer.name }}. Bienvenido/a a {{ shop.name }}.\nNos alegra tenerte aquí. A partir de ahora vas a encontrar todo lo que necesitas en un solo lugar, con la atención que mereces.\nOferta de bienvenida\n \n10% en tu primera compra\n \n+ envío gratis en tu primer pedido\n \nBIENVENIDO10\n \nVálido por 7 días · Sin monto mínimo · Solo primera compra\nPor qué elegir {{ shop.name }}\n30+\nAños en el mercado\n \n10K+\nClientes satisfechos\n \n24h\nTiempo de respuesta\nExplorar catálogo →\n¿Tienes dudas?\nEscríbenos →\nExplora por categoría\n \nNovedades\nMás vendidos\nOfertas\nAccesorios', NULL, 'prestashop_mail', 1, '2026-07-02 22:13:15', '2026-07-08 12:41:35'),
(7, 1, 1, NULL, 'cart', 'Carrito 01 - Dudas', '{{ customer.firstname }}, ¿te quedó alguna duda?', 'mailsendvx_default', '<!-- ===================== HERO ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"padding:40px 40px 24px 40px;\">\r\n      <!-- EDITAR AQUÍ: color de marca (texto y fondo de la píldora) -->\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin-bottom:16px;\">\r\n        <tr>\r\n          <td style=\"background-color:#EEF2F6; border-radius:20px; padding:5px 12px; font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">\r\n            Antes de decidir\r\n          </td>\r\n        </tr>\r\n      </table>\r\n\r\n      <h1 style=\"margin:0 0 14px 0; font-family:Arial, Helvetica, sans-serif; font-size:26px; line-height:1.3; font-weight:bold; color:#201E1A;\">\r\n        {{ customer.firstname|default(customer.name) }}, ¿te quedó alguna duda?\r\n      </h1>\r\n\r\n      <p style=\"margin:0 0 14px 0; font-family:Arial, Helvetica, sans-serif; font-size:15px; line-height:1.6; color:#6E6A62;\">\r\n        Está bien tener dudas. A veces la opción correcta depende de detalles que no siempre se ven a simple vista — la talla, la compatibilidad, o cuál versión te conviene más.\r\n      </p>\r\n      <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:15px; line-height:1.6; color:#6E6A62;\">\r\n        Por eso tenemos a nuestro equipo disponible para ayudarte. Solo respuestas reales. Sin costo, sin compromiso.\r\n      </p>\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<!-- ===================== SOPORTE PRE-VENTA (OPCIONAL) ===================== -->\r\n<!-- Quitar todo este bloque si el proyecto no ofrece asesoría pre-venta -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"padding:0 40px 24px 40px;\">\r\n      <!-- EDITAR AQUÍ: color de marca (fondo de la tarjeta) -->\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color:#1B3A5C; border-radius:14px;\">\r\n        <tr>\r\n          <td style=\"padding:32px;\">\r\n            <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin-bottom:16px;\">\r\n              <tr>\r\n                <td style=\"background-color:rgba(255,255,255,0.15); border-radius:20px; padding:5px 12px; font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#FFFFFF;\">\r\n                  Te ayudamos a decidir\r\n                </td>\r\n              </tr>\r\n            </table>\r\n\r\n            <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n              <tr>\r\n                <td style=\"padding-bottom:12px; font-family:Arial, Helvetica, sans-serif; font-size:13.5px; color:rgba(255,255,255,0.75);\">\r\n                  ✓  Confirma si el producto es el indicado para lo que necesitas\r\n                </td>\r\n              </tr>\r\n              <tr>\r\n                <td style=\"padding-bottom:12px; font-family:Arial, Helvetica, sans-serif; font-size:13.5px; color:rgba(255,255,255,0.75);\">\r\n                  ✓  Te ayuda a comparar entre opciones similares\r\n                </td>\r\n              </tr>\r\n              <tr>\r\n                <td style=\"padding-bottom:24px; font-family:Arial, Helvetica, sans-serif; font-size:13.5px; color:rgba(255,255,255,0.75);\">\r\n                  ✓  Resuelve dudas sobre talla, compatibilidad o uso\r\n                </td>\r\n              </tr>\r\n            </table>\r\n\r\n            <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n              <tr>\r\n                <td style=\"background-color:#25D366; border-radius:8px;\">\r\n                  <a href=\"{{ shop.contact_url|default(shop.url) }}\" style=\"display:inline-block; padding:13px 26px; font-family:Arial, Helvetica, sans-serif; font-size:14px; font-weight:bold; color:#FFFFFF; text-decoration:none;\">\r\n                    Hablar con nuestro equipo\r\n                  </a>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<!-- ===================== CARRITO (OBLIGATORIO) ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"padding:0 40px 24px 40px;\">\r\n\r\n      <!-- EDITAR AQUÍ: color de marca (texto y fondo de la píldora) -->\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin-bottom:16px;\">\r\n        <tr>\r\n          <td style=\"background-color:#EEF2F6; border-radius:20px; padding:5px 12px; font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">\r\n            Tu carrito sigue guardado\r\n          </td>\r\n        </tr>\r\n      </table>\r\n\r\n      {% for item in cart.items %}\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"border-bottom:1px solid #E6E1D8;\">\r\n        <tr>\r\n          <td width=\"48\" valign=\"top\" style=\"padding:16px 14px 16px 0;\">\r\n            {% if item.image_url %}\r\n            <img src=\"{{ item.image_url }}\" alt=\"{{ item.name }}\" width=\"48\" style=\"display:block; border-radius:8px; border:1px solid #E6E1D8;\">\r\n            {% else %}\r\n            <table role=\"presentation\" width=\"48\" height=\"48\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color:#F6F4F0; border:1px solid #E6E1D8; border-radius:8px;\"><tr><td> </td></tr></table>\r\n            {% endif %}\r\n          </td>\r\n          <td valign=\"top\" style=\"padding:16px 0;\">\r\n            <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:13.5px; font-weight:600; color:#201E1A;\">{{ item.name }}</p>\r\n            <p style=\"margin:2px 0 0 0; font-family:Arial, Helvetica, sans-serif; font-size:11.5px; color:#6E6A62;\">Cantidad: {{ item.quantity }}</p>\r\n          </td>\r\n          <td valign=\"top\" align=\"right\" style=\"padding:16px 0;\">\r\n            <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:14px; font-weight:bold; color:#201E1A; white-space:nowrap;\">${{ item.total_price }}</p>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n      {% endfor %}\r\n\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin-top:8px; padding-top:16px;\">\r\n        <tr>\r\n          <td style=\"font-family:Arial, Helvetica, sans-serif; font-size:14px; font-weight:bold; color:#201E1A;\">Total</td>\r\n          <td align=\"right\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:16px; font-weight:bold; color:#201E1A;\">${{ cart.total }}</td>\r\n        </tr>\r\n      </table>\r\n\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin-top:28px;\">\r\n        <tr>\r\n          <td align=\"center\">\r\n            <!-- EDITAR AQUÍ: color de marca (fondo del botón) -->\r\n            <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n              <tr>\r\n                <td style=\"background-color:#1B3A5C; border-radius:8px;\">\r\n                  <a href=\"{{ cart.recovery_url }}\" style=\"display:inline-block; padding:14px 28px; font-family:Arial, Helvetica, sans-serif; font-size:14px; font-weight:bold; color:#FFFFFF; text-decoration:none;\">\r\n                    Completar compra →\r\n                  </a>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n\r\n    </td>\r\n  </tr>\r\n</table>', 'Antes de decidir\n{{ customer.firstname|default(customer.name) }}, ¿te quedó alguna duda?\nEstá bien tener dudas. A veces la opción correcta depende de detalles que no siempre se ven a simple vista — la talla, la compatibilidad, o cuál versión te conviene más.\nPor eso tenemos a nuestro equipo disponible para ayudarte. Solo respuestas reales. Sin costo, sin compromiso.\nTe ayudamos a decidir\n✓  Confirma si el producto es el indicado para lo que necesitas\n✓  Te ayuda a comparar entre opciones similares\n✓  Resuelve dudas sobre talla, compatibilidad o uso\nHablar con nuestro equipo\nTu carrito sigue guardado\n{% for item in cart.items %}\n{% if item.image_url %}\n{% else %}\n \n{% endif %}\n{{ item.name }}\nCantidad: {{ item.quantity }}\n${{ item.total_price }}\n{% endfor %}\nTotal\n${{ cart.total }}\nCompletar compra →', NULL, 'prestashop_mail', 1, '2026-07-02 22:35:47', '2026-07-08 12:44:31'),
(8, 1, 1, NULL, 'cart', 'Carrito 02 - Recordatorio', '{{ customer.firstname }}, dejaste algo en el camino', 'mailsendvx_default', '<!-- ===================== HERO ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"padding:40px 40px 24px 40px;\">\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin-bottom:16px;\">\r\n        <tr>\r\n          <td style=\"background-color:#EEF2F6; border-radius:20px; padding:5px 12px; font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">\r\n            Carrito pendiente\r\n          </td>\r\n        </tr>\r\n      </table>\r\n\r\n      <h1 style=\"margin:0 0 14px 0; font-family:Arial, Helvetica, sans-serif; font-size:26px; line-height:1.3; font-weight:bold; color:#201E1A;\">\r\n        {{ customer.firstname|default(customer.name) }}, dejaste algo en el camino.\r\n      </h1>\r\n\r\n      <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:15px; line-height:1.6; color:#6E6A62;\">\r\n        Notamos que saliste antes de completar tu compra. Tus productos siguen guardados — te los dejamos aquí para que no tengas que buscarlos de nuevo.\r\n      </p>\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<!-- ===================== CARRITO Y TOTALES (OBLIGATORIO) ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"padding:0 40px 24px 40px;\">\r\n\r\n      {% for item in cart.items %}\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"border-bottom:1px solid #E6E1D8;\">\r\n        <tr>\r\n          <td width=\"56\" valign=\"top\" style=\"padding:16px 16px 16px 0;\">\r\n            {% if item.image_url %}\r\n            <img src=\"{{ item.image_url }}\" alt=\"{{ item.name }}\" width=\"56\" style=\"display:block; border-radius:8px; border:1px solid #E6E1D8;\">\r\n            {% else %}\r\n            <table role=\"presentation\" width=\"56\" height=\"56\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color:#F6F4F0; border:1px solid #E6E1D8; border-radius:8px;\"><tr><td>&nbsp;</td></tr></table>\r\n            {% endif %}\r\n          </td>\r\n          <td valign=\"top\" style=\"padding:16px 0;\">\r\n            <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:14px; font-weight:bold; color:#201E1A;\">{{ item.name }}</p>\r\n            <p style=\"margin:3px 0 0 0; font-family:Arial, Helvetica, sans-serif; font-size:11.5px; color:#6E6A62;\">Cantidad: {{ item.quantity }}</p>\r\n          </td>\r\n          <td valign=\"top\" align=\"right\" style=\"padding:16px 0;\">\r\n            <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:15px; font-weight:bold; color:#201E1A; white-space:nowrap;\">${{ item.total_price }}</p>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n      {% endfor %}\r\n\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin-top:6px;\">\r\n        <tr>\r\n          <td style=\"padding:10px 0; font-family:Arial, Helvetica, sans-serif; font-size:13px; color:#6E6A62;\">Subtotal</td>\r\n          <td align=\"right\" style=\"padding:10px 0; font-family:Arial, Helvetica, sans-serif; font-size:13px; color:#6E6A62;\">${{ cart.totals.products }}</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding:10px 0; font-family:Arial, Helvetica, sans-serif; font-size:13px; color:#6E6A62;\">Envío estimado</td>\r\n          <td align=\"right\" style=\"padding:10px 0; font-family:Arial, Helvetica, sans-serif; font-size:13px; font-weight:600; color:#1B3A5C;\">\r\n            {% if cart.totals.shipping %}${{ cart.totals.shipping }}{% else %}Calcular al finalizar{% endif %}\r\n          </td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding-top:14px; border-top:1px solid #E6E1D8; font-family:Arial, Helvetica, sans-serif; font-size:16px; font-weight:bold; color:#201E1A;\">Total</td>\r\n          <td align=\"right\" style=\"padding-top:14px; border-top:1px solid #E6E1D8; font-family:Arial, Helvetica, sans-serif; font-size:16px; font-weight:bold; color:#201E1A;\">${{ cart.total }}</td>\r\n        </tr>\r\n      </table>\r\n\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin-top:28px;\">\r\n        <tr>\r\n          <td align=\"center\">\r\n            <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n              <tr>\r\n                <td style=\"background-color:#1B3A5C; border-radius:8px;\">\r\n                  <a href=\"{{ cart.recovery_url }}\" style=\"display:inline-block; padding:14px 28px; font-family:Arial, Helvetica, sans-serif; font-size:14px; font-weight:bold; color:#FFFFFF; text-decoration:none;\">\r\n                    Completar mi compra →\r\n                  </a>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<!-- ===================== SOPORTE PRE-VENTA — mención liviana (OPCIONAL) ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"background-color:#F6F4F0; padding:28px 40px; text-align:center;\">\r\n      <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:13px; color:#6E6A62;\">\r\n        ¿Tienes dudas antes de comprar?\r\n        <a href=\"{{ shop.contact_url|default(shop.url) }}\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:13px; font-weight:600; color:#1B3A5C; text-decoration:none;\">Habla con nuestro equipo →</a>\r\n      </p>\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<!-- ===================== BADGES DE CONFIANZA (OPCIONAL) ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"padding:40px;\">\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n        <tr>\r\n          <td width=\"33%\" valign=\"top\" style=\"padding-right:6px;\">\r\n            <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"border:1px solid #E6E1D8; border-radius:10px;\">\r\n              <tr>\r\n                <td style=\"padding:16px 12px; text-align:center;\">\r\n                  <p style=\"margin:0 0 4px 0; font-family:Arial, Helvetica, sans-serif; font-size:12.5px; font-weight:bold; color:#201E1A;\">Envío confiable</p>\r\n                  <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:10.5px; color:#6E6A62; line-height:1.4;\">Entrega en los tiempos estimados</p>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n          <td width=\"34%\" valign=\"top\" style=\"padding:0 6px;\">\r\n            <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"border:1px solid #E6E1D8; border-radius:10px;\">\r\n              <tr>\r\n                <td style=\"padding:16px 12px; text-align:center;\">\r\n                  <p style=\"margin:0 0 4px 0; font-family:Arial, Helvetica, sans-serif; font-size:12.5px; font-weight:bold; color:#201E1A;\">Pago protegido</p>\r\n                  <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:10.5px; color:#6E6A62; line-height:1.4;\">Métodos de pago verificados</p>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n          <td width=\"33%\" valign=\"top\" style=\"padding-left:6px;\">\r\n            <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"border:1px solid #E6E1D8; border-radius:10px;\">\r\n              <tr>\r\n                <td style=\"padding:16px 12px; text-align:center;\">\r\n                  <p style=\"margin:0 0 4px 0; font-family:Arial, Helvetica, sans-serif; font-size:12.5px; font-weight:bold; color:#201E1A;\">Garantía de fábrica</p>\r\n                  <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:10.5px; color:#6E6A62; line-height:1.4;\">En todos los productos</p>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n</table>', 'Carrito pendiente\n{{ customer.firstname|default(customer.name) }}, dejaste algo en el camino.\nNotamos que saliste antes de completar tu compra. Tus productos siguen guardados — te los dejamos aquí para que no tengas que buscarlos de nuevo.\n{% for item in cart.items %}\n{% if item.image_url %}\n{% else %}\n \n{% endif %}\n{{ item.name }}\nCantidad: {{ item.quantity }}\n${{ item.total_price }}\n{% endfor %}\nSubtotal\n${{ cart.totals.products }}\nEnvío estimado\n{% if cart.totals.shipping %}${{ cart.totals.shipping }}{% else %}Calcular al finalizar{% endif %}\nTotal\n${{ cart.total }}\nCompletar mi compra →\n¿Tienes dudas antes de comprar?\nHabla con nuestro equipo →\nEnvío confiable\nEntrega en los tiempos estimados\nPago protegido\nMétodos de pago verificados\nGarantía de fábrica\nEn todos los productos', NULL, 'prestashop_mail', 1, '2026-07-07 15:30:30', '2026-07-07 15:30:30'),
(9, 1, 1, NULL, 'cart', 'Carrito 03 - Último recordatorio', '{{ customer.firstname }}, cerramos el carrito mañana', 'mailsendvx_default', '<!-- ===================== BANDA DE URGENCIA ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"background-color:#FDF3E7; border-bottom:2px solid #FAD5A0; padding:14px 40px;\">\r\n      <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:12.5px; color:#8A4508;\">\r\n        <strong>Tu carrito se libera en 24 horas.</strong> Este es nuestro último recordatorio.\r\n      </p>\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<!-- ===================== HERO ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"padding:40px 40px 24px 40px;\">\r\n      <h1 style=\"margin:0 0 14px 0; font-family:Arial, Helvetica, sans-serif; font-size:26px; line-height:1.3; font-weight:bold; color:#201E1A;\">\r\n        {{ customer.firstname|default(customer.name) }}, cerramos el carrito mañana.\r\n      </h1>\r\n      <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:15px; line-height:1.6; color:#6E6A62;\">\r\n        Después de esta fecha, los productos vuelven al catálogo general y no podemos garantizar disponibilidad al mismo precio.\r\n      </p>\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<!-- ===================== CARRITO Y TOTAL (OBLIGATORIO) ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"padding:0 40px;\">\r\n\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin-bottom:16px;\">\r\n        <tr>\r\n          <td style=\"background-color:#EEF2F6; border-radius:20px; padding:5px 12px; font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">\r\n            Los productos que dejaste\r\n          </td>\r\n        </tr>\r\n      </table>\r\n\r\n      {% for item in cart.items %}\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"border-bottom:1px solid #E6E1D8;\">\r\n        <tr>\r\n          <td width=\"48\" valign=\"top\" style=\"padding:16px 14px 16px 0;\">\r\n            {% if item.image_url %}\r\n            <img src=\"{{ item.image_url }}\" alt=\"{{ item.name }}\" width=\"48\" style=\"display:block; border-radius:8px; border:1px solid #E6E1D8;\">\r\n            {% else %}\r\n            <table role=\"presentation\" width=\"48\" height=\"48\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color:#F6F4F0; border:1px solid #E6E1D8; border-radius:8px;\"><tr><td>&nbsp;</td></tr></table>\r\n            {% endif %}\r\n          </td>\r\n          <td valign=\"top\" style=\"padding:16px 0;\">\r\n            <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:13.5px; font-weight:600; color:#201E1A;\">{{ item.name }}</p>\r\n            <p style=\"margin:2px 0 0 0; font-family:Arial, Helvetica, sans-serif; font-size:11.5px; color:#6E6A62;\">Cantidad: {{ item.quantity }}</p>\r\n          </td>\r\n          <td valign=\"top\" align=\"right\" style=\"padding:16px 0;\">\r\n            <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:14px; font-weight:bold; color:#201E1A; white-space:nowrap;\">${{ item.total_price }}</p>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n      {% endfor %}\r\n\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin-top:8px; padding-top:14px;\">\r\n        <tr>\r\n          <td style=\"font-family:Arial, Helvetica, sans-serif; font-size:16px; font-weight:bold; color:#201E1A;\">Total</td>\r\n          <td align=\"right\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:16px; font-weight:bold; color:#201E1A;\">${{ cart.total }}</td>\r\n        </tr>\r\n      </table>\r\n\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<!-- ===================== INCENTIVO FINAL (OPCIONAL — ver notas) ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"padding:40px;\">\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color:#FDF3E7; border:1px solid #FAD5A0; border-radius:12px;\">\r\n        <tr>\r\n          <td style=\"padding:24px;\">\r\n            <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin-bottom:12px;\">\r\n              <tr>\r\n                <td style=\"background-color:#C4690A; border-radius:20px; padding:4px 12px; font-family:Arial, Helvetica, sans-serif; font-size:10px; font-weight:bold; color:#FFFFFF;\">\r\n                  Incentivo final\r\n                </td>\r\n              </tr>\r\n            </table>\r\n            <p style=\"margin:0 0 8px 0; font-family:Arial, Helvetica, sans-serif; font-size:22px; font-weight:bold; color:#C4690A;\">5% off adicional</p>\r\n            <p style=\"margin:0 0 16px 0; font-family:Arial, Helvetica, sans-serif; font-size:12px; color:#8A4508;\">Aplica solo si completas la compra hoy. Sin monto mínimo.</p>\r\n            <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n              <tr>\r\n                <td style=\"background-color:#FFFFFF; border:1px solid #FAD5A0; border-radius:8px; padding:8px 18px; font-family:Arial, Helvetica, sans-serif; font-size:16px; font-weight:bold; color:#C4690A;\">\r\n                  HOY5\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<!-- ===================== CTA ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"padding:0 40px 24px 40px; text-align:center;\">\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n        <tr>\r\n          <td style=\"background-color:#1B3A5C; border-radius:8px;\">\r\n            <a href=\"{{ cart.recovery_url }}\" style=\"display:block; padding:14px 28px; font-family:Arial, Helvetica, sans-serif; font-size:14px; font-weight:bold; color:#FFFFFF; text-decoration:none; text-align:center;\">\r\n              Completar compra con 5% off →\r\n            </a>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin-top:12px;\">\r\n        <tr>\r\n          <td style=\"border:1px solid #E6E1D8; border-radius:8px;\">\r\n            <a href=\"{{ shop.contact_url|default(shop.url) }}\" style=\"display:block; padding:11px 28px; font-family:Arial, Helvetica, sans-serif; font-size:13px; font-weight:600; color:#1B3A5C; text-decoration:none; text-align:center;\">\r\n              Consultar con nuestro equipo primero\r\n            </a>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n      <p style=\"margin:18px 0 0 0; font-family:Arial, Helvetica, sans-serif; font-size:11px; color:#6E6A62;\">\r\n        ¿Ya no te interesa? <a href=\"#\" style=\"color:#6E6A62; text-decoration:underline;\">Vaciar carrito</a>\r\n      </p>\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<!-- ===================== LISTA DE CONFIANZA (OPCIONAL) ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"padding:0 40px 40px 40px;\">\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin-bottom:16px;\">\r\n        <tr>\r\n          <td style=\"background-color:#EEF2F6; border-radius:20px; padding:5px 12px; font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">\r\n            Por qué comprar aquí\r\n          </td>\r\n        </tr>\r\n      </table>\r\n\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n        <tr>\r\n          <td width=\"28\" valign=\"top\" style=\"padding:14px 0;\">\r\n            <table role=\"presentation\" width=\"28\" height=\"28\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color:#EEF2F6; border-radius:14px;\"><tr><td align=\"center\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:12px; color:#1B3A5C;\">✓</td></tr></table>\r\n          </td>\r\n          <td valign=\"top\" style=\"padding:14px 0 14px 14px;\">\r\n            <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:13px; font-weight:bold; color:#201E1A;\">Productos 100% originales</p>\r\n            <p style=\"margin:2px 0 0 0; font-family:Arial, Helvetica, sans-serif; font-size:11.5px; color:#6E6A62;\">Con garantía y respaldo de la tienda</p>\r\n          </td>\r\n        </tr>\r\n        <tr>\r\n          <td width=\"28\" valign=\"top\" style=\"padding:14px 0;\">\r\n            <table role=\"presentation\" width=\"28\" height=\"28\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color:#EEF2F6; border-radius:14px;\"><tr><td align=\"center\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:12px; color:#1B3A5C;\">✓</td></tr></table>\r\n          </td>\r\n          <td valign=\"top\" style=\"padding:14px 0 14px 14px;\">\r\n            <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:13px; font-weight:bold; color:#201E1A;\">Pago 100% seguro</p>\r\n            <p style=\"margin:2px 0 0 0; font-family:Arial, Helvetica, sans-serif; font-size:11.5px; color:#6E6A62;\">Métodos de pago verificados</p>\r\n          </td>\r\n        </tr>\r\n        <tr>\r\n          <td width=\"28\" valign=\"top\" style=\"padding:14px 0;\">\r\n            <table role=\"presentation\" width=\"28\" height=\"28\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color:#EEF2F6; border-radius:14px;\"><tr><td align=\"center\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:12px; color:#1B3A5C;\">✓</td></tr></table>\r\n          </td>\r\n          <td valign=\"top\" style=\"padding:14px 0 14px 14px;\">\r\n            <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:13px; font-weight:bold; color:#201E1A;\">Opciones de entrega flexibles</p>\r\n            <p style=\"margin:2px 0 0 0; font-family:Arial, Helvetica, sans-serif; font-size:11.5px; color:#6E6A62;\">Envío a domicilio o retiro, según disponibilidad</p>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n</table>', 'Tu carrito se libera en 24 horas. Este es nuestro último recordatorio.\n{{ customer.firstname|default(customer.name) }}, cerramos el carrito mañana.\nDespués de esta fecha, los productos vuelven al catálogo general y no podemos garantizar disponibilidad al mismo precio.\nLos productos que dejaste\n{% for item in cart.items %}\n{% if item.image_url %}\n{% else %}\n \n{% endif %}\n{{ item.name }}\nCantidad: {{ item.quantity }}\n${{ item.total_price }}\n{% endfor %}\nTotal\n${{ cart.total }}\nIncentivo final\n5% off adicional\nAplica solo si completas la compra hoy. Sin monto mínimo.\nHOY5\nCompletar compra con 5% off →\nConsultar con nuestro equipo primero\n¿Ya no te interesa? Vaciar carrito\nPor qué comprar aquí\n✓\nProductos 100% originales\nCon garantía y respaldo de la tienda\n✓\nPago 100% seguro\nMétodos de pago verificados\n✓\nOpciones de entrega flexibles\nEnvío a domicilio o retiro, según disponibilidad', NULL, 'prestashop_mail', 1, '2026-07-07 15:31:46', '2026-07-07 15:31:46');
INSERT INTO `ps_mailsendvx_template` (`id_mailsendvx_template`, `id_shop`, `id_lang`, `event_name`, `context_type`, `name`, `subject`, `mail_template`, `html_content`, `text_content`, `json_design`, `provider`, `active`, `date_add`, `date_upd`) VALUES
(10, 1, 1, NULL, 'newsletter', 'Suscripción 02 - Historia y confianza', '{{ customer.firstname|default(customer.name) }}, te contamos quiénes somos', 'mailsendvx_default', '<!-- ===================== HERO ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"padding:40px 40px 24px 40px;\">\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin-bottom:16px;\">\r\n        <tr>\r\n          <td style=\"background-color:#EEF2F6; border-radius:20px; padding:5px 12px; font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">\r\n            Nuestra historia\r\n          </td>\r\n        </tr>\r\n      </table>\r\n\r\n      <h1 style=\"margin:0 0 14px 0; font-family:Arial, Helvetica, sans-serif; font-size:24px; line-height:1.3; font-weight:bold; color:#201E1A;\">\r\n        Hola, {{ customer.firstname|default(customer.name) }} — te contamos quiénes somos.\r\n      </h1>\r\n\r\n      <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:15px; line-height:1.6; color:#6E6A62;\">\r\n        En {{ shop.name }} creemos que comprar bien empieza por elegir bien con quién comprar. Por eso ponemos a tu disposición todo lo que necesitas, con la calidad y el respaldo que buscas.\r\n      </p>\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<!-- ===================== ESTADÍSTICAS DE CONFIANZA (OPCIONAL) ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"padding:0 40px 24px 40px;\">\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"border:1px solid #E6E1D8; border-radius:12px;\">\r\n        <tr>\r\n          <td width=\"25%\" style=\"padding:22px 8px; text-align:center; border-right:1px solid #E6E1D8;\">\r\n            <p style=\"margin:0 0 4px 0; font-family:Arial, Helvetica, sans-serif; font-size:22px; font-weight:bold; color:#1B3A5C;\">30+</p>\r\n            <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:10.5px; color:#6E6A62; line-height:1.4;\">Años en<br>el mercado</p>\r\n          </td>\r\n          <td width=\"25%\" style=\"padding:22px 8px; text-align:center; border-right:1px solid #E6E1D8;\">\r\n            <p style=\"margin:0 0 4px 0; font-family:Arial, Helvetica, sans-serif; font-size:22px; font-weight:bold; color:#1B3A5C;\">10K+</p>\r\n            <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:10.5px; color:#6E6A62; line-height:1.4;\">Clientes<br>atendidos</p>\r\n          </td>\r\n          <td width=\"25%\" style=\"padding:22px 8px; text-align:center; border-right:1px solid #E6E1D8;\">\r\n            <p style=\"margin:0 0 4px 0; font-family:Arial, Helvetica, sans-serif; font-size:22px; font-weight:bold; color:#1B3A5C;\">12</p>\r\n            <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:10.5px; color:#6E6A62; line-height:1.4;\">Ciudades con<br>cobertura</p>\r\n          </td>\r\n          <td width=\"25%\" style=\"padding:22px 8px; text-align:center;\">\r\n            <p style=\"margin:0 0 4px 0; font-family:Arial, Helvetica, sans-serif; font-size:22px; font-weight:bold; color:#1B3A5C;\">5K+</p>\r\n            <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:10.5px; color:#6E6A62; line-height:1.4;\">Productos en<br>catálogo</p>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<!-- ===================== DIFERENCIADORES (OPCIONAL / AJUSTABLE) ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"padding:0 40px 24px 40px;\">\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin-bottom:16px;\">\r\n        <tr>\r\n          <td style=\"background-color:#EEF2F6; border-radius:20px; padding:5px 12px; font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">\r\n            Lo que nos hace diferentes\r\n          </td>\r\n        </tr>\r\n      </table>\r\n\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color:#F6F4F0; border-radius:0 8px 8px 0; border-left:3px solid #1B3A5C; margin-bottom:14px;\">\r\n        <tr>\r\n          <td style=\"padding:18px 20px;\">\r\n            <p style=\"margin:0 0 4px 0; font-family:Arial, Helvetica, sans-serif; font-size:14px; font-weight:bold; color:#201E1A;\">Atención personalizada</p>\r\n            <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:13.5px; color:#6E6A62; line-height:1.5;\">Te acompañamos antes, durante y después de tu compra. No vendemos por vender — te ayudamos a elegir lo que realmente necesitas.</p>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color:#F6F4F0; border-radius:0 8px 8px 0; border-left:3px solid #1B3A5C; margin-bottom:14px;\">\r\n        <tr>\r\n          <td style=\"padding:18px 20px;\">\r\n            <p style=\"margin:0 0 4px 0; font-family:Arial, Helvetica, sans-serif; font-size:14px; font-weight:bold; color:#201E1A;\">Todo en un solo lugar</p>\r\n            <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:13.5px; color:#6E6A62; line-height:1.5;\">Un catálogo amplio para que encuentres lo que buscas sin tener que recurrir a varias tiendas distintas.</p>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color:#F6F4F0; border-radius:0 8px 8px 0; border-left:3px solid #1B3A5C;\">\r\n        <tr>\r\n          <td style=\"padding:18px 20px;\">\r\n            <p style=\"margin:0 0 4px 0; font-family:Arial, Helvetica, sans-serif; font-size:14px; font-weight:bold; color:#201E1A;\">Cobertura de envío real</p>\r\n            <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:13.5px; color:#6E6A62; line-height:1.5;\">Entregamos a nivel nacional, con tiempos claros y transportistas confiables.</p>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<!-- ===================== TESTIMONIO (OPCIONAL) ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"background-color:#F6F4F0; padding:40px;\">\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin-bottom:16px;\">\r\n        <tr>\r\n          <td style=\"background-color:#EEF2F6; border-radius:20px; padding:5px 12px; font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">\r\n            Lo que dicen nuestros clientes\r\n          </td>\r\n        </tr>\r\n      </table>\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color:#FFFFFF; border-radius:12px;\">\r\n        <tr>\r\n          <td style=\"padding:28px;\">\r\n            <p style=\"margin:0 0 14px 0; font-family:Arial, Helvetica, sans-serif; font-size:13px; letter-spacing:2px; color:#1B3A5C;\">★★★★★</p>\r\n            <p style=\"margin:0 0 20px 0; font-family:Arial, Helvetica, sans-serif; font-size:15px; line-height:1.7; color:#201E1A;\">\"Encontré justo lo que necesitaba y la atención fue excelente de principio a fin. Una experiencia de compra como pocas.\"</p>\r\n            <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n              <tr>\r\n                <td style=\"width:36px; height:36px; background-color:#1B3A5C; border-radius:18px; text-align:center; font-family:Arial, Helvetica, sans-serif; font-size:12px; font-weight:bold; color:#FFFFFF;\">MT</td>\r\n                <td style=\"padding-left:12px;\">\r\n                  <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:13px; font-weight:bold; color:#201E1A;\">María Torres</p>\r\n                  <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:11px; color:#6E6A62;\">Compra verificada</p>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<!-- ===================== CTA FINAL ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"padding:40px; text-align:center;\">\r\n      <p style=\"margin:0 0 20px 0; font-family:Arial, Helvetica, sans-serif; font-size:15px; color:#6E6A62;\">\r\n        ¿Todo listo para tu primera compra? Recuerda que tienes el código <strong style=\"color:#201E1A;\">BIENVENIDO10</strong>.\r\n      </p>\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin:0 auto;\">\r\n        <tr>\r\n          <td style=\"background-color:#1B3A5C; border-radius:8px;\">\r\n            <a href=\"{{ shop.url }}\" style=\"display:inline-block; padding:14px 28px; font-family:Arial, Helvetica, sans-serif; font-size:14px; font-weight:bold; color:#FFFFFF; text-decoration:none;\">\r\n              Ir al catálogo →\r\n            </a>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n      <p style=\"margin:20px 0 0 0; font-family:Arial, Helvetica, sans-serif; font-size:13px; color:#6E6A62;\">\r\n        ¿Tienes dudas?\r\n        <a href=\"{{ shop.contact_url|default(shop.url) }}\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:13px; font-weight:bold; color:#1B3A5C; text-decoration:none;\">Escríbenos →</a>\r\n      </p>\r\n    </td>\r\n  </tr>\r\n</table>', 'Nuestra historia\nHola, {{ customer.firstname|default(customer.name) }} — te contamos quiénes somos.\nEn {{ shop.name }} creemos que comprar bien empieza por elegir bien con quién comprar. Por eso ponemos a tu disposición todo lo que necesitas, con la calidad y el respaldo que buscas.\n30+\nAños en\nel mercado\n10K+\nClientes\natendidos\n12\nCiudades con\ncobertura\n5K+\nProductos en\ncatálogo\nLo que nos hace diferentes\nAtención personalizada\nTe acompañamos antes, durante y después de tu compra. No vendemos por vender — te ayudamos a elegir lo que realmente necesitas.\nTodo en un solo lugar\nUn catálogo amplio para que encuentres lo que buscas sin tener que recurrir a varias tiendas distintas.\nCobertura de envío real\nEntregamos a nivel nacional, con tiempos claros y transportistas confiables.\nLo que dicen nuestros clientes\n★★★★★\n\"Encontré justo lo que necesitaba y la atención fue excelente de principio a fin. Una experiencia de compra como pocas.\"\nMT\nMaría Torres\nCompra verificada\n¿Todo listo para tu primera compra? Recuerda que tienes el código BIENVENIDO10.\nIr al catálogo →\n¿Tienes dudas?\nEscríbenos →', NULL, 'prestashop_mail', 1, '2026-07-07 15:58:17', '2026-07-07 15:58:17'),
(11, 1, 1, NULL, 'newsletter', 'Suscripción 03 - Catálogo', '¿Qué estás buscando, {{ customer.firstname|default(customer.name) }}?', 'mailsendvx_default', '<!-- ===================== HERO ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"padding:40px 40px 24px 40px;\">\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin-bottom:16px;\">\r\n        <tr>\r\n          <td style=\"background-color:#EEF2F6; border-radius:20px; padding:5px 12px; font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">\r\n            Catálogo\r\n          </td>\r\n        </tr>\r\n      </table>\r\n\r\n      <h1 style=\"margin:0 0 14px 0; font-family:Arial, Helvetica, sans-serif; font-size:26px; line-height:1.3; font-weight:bold; color:#201E1A;\">\r\n        ¿Qué estás buscando?\r\n      </h1>\r\n\r\n      <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:15px; line-height:1.6; color:#6E6A62;\">\r\n        Para que te sea fácil encontrar lo que necesitas, aquí tienes un mapa rápido de nuestras categorías.\r\n      </p>\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<!-- ===================== CATEGORÍAS ===================== -->\r\n<!-- Duplicar/eliminar filas y celdas según el número real de categorías del comercio -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"padding:0 40px 24px 40px;\">\r\n\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n        <tr>\r\n          <td width=\"48%\" valign=\"top\">\r\n            <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"border:1px solid #E6E1D8; border-radius:10px;\">\r\n              <tr>\r\n                <td style=\"padding:18px;\">\r\n                  <p style=\"margin:0 0 6px 0; font-family:Arial, Helvetica, sans-serif; font-size:14.5px; font-weight:bold; color:#201E1A;\">Hogar</p>\r\n                  <p style=\"margin:0 0 12px 0; font-family:Arial, Helvetica, sans-serif; font-size:12.5px; line-height:1.55; color:#6E6A62;\">Todo lo que necesitas para tu espacio, en un solo lugar.</p>\r\n                  <a href=\"{{ shop.url }}\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:12px; font-weight:bold; color:#1B3A5C; text-decoration:none;\">Ver categoría →</a>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n          <td width=\"4%\">&nbsp;</td>\r\n          <td width=\"48%\" valign=\"top\">\r\n            <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"border:1px solid #E6E1D8; border-radius:10px;\">\r\n              <tr>\r\n                <td style=\"padding:18px;\">\r\n                  <p style=\"margin:0 0 6px 0; font-family:Arial, Helvetica, sans-serif; font-size:14.5px; font-weight:bold; color:#201E1A;\">Tecnología y electrónica</p>\r\n                  <p style=\"margin:0 0 12px 0; font-family:Arial, Helvetica, sans-serif; font-size:12.5px; line-height:1.55; color:#6E6A62;\">Productos confiables, con garantía y soporte incluido.</p>\r\n                  <a href=\"{{ shop.url }}\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:12px; font-weight:bold; color:#1B3A5C; text-decoration:none;\">Ver categoría →</a>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\"><tr><td style=\"height:16px; line-height:16px;\">&nbsp;</td></tr></table>\r\n\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n        <tr>\r\n          <td width=\"48%\" valign=\"top\">\r\n            <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"border:1px solid #E6E1D8; border-radius:10px;\">\r\n              <tr>\r\n                <td style=\"padding:18px;\">\r\n                  <p style=\"margin:0 0 6px 0; font-family:Arial, Helvetica, sans-serif; font-size:14.5px; font-weight:bold; color:#201E1A;\">Cuidado personal</p>\r\n                  <p style=\"margin:0 0 12px 0; font-family:Arial, Helvetica, sans-serif; font-size:12.5px; line-height:1.55; color:#6E6A62;\">Selección pensada para tu rutina diaria.</p>\r\n                  <a href=\"{{ shop.url }}\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:12px; font-weight:bold; color:#1B3A5C; text-decoration:none;\">Ver categoría →</a>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n          <td width=\"4%\">&nbsp;</td>\r\n          <td width=\"48%\" valign=\"top\">\r\n            <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"border:1px solid #E6E1D8; border-radius:10px;\">\r\n              <tr>\r\n                <td style=\"padding:18px;\">\r\n                  <p style=\"margin:0 0 6px 0; font-family:Arial, Helvetica, sans-serif; font-size:14.5px; font-weight:bold; color:#201E1A;\">Accesorios</p>\r\n                  <p style=\"margin:0 0 12px 0; font-family:Arial, Helvetica, sans-serif; font-size:12.5px; line-height:1.55; color:#6E6A62;\">Los detalles que completan lo que ya tienes.</p>\r\n                  <a href=\"{{ shop.url }}\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:12px; font-weight:bold; color:#1B3A5C; text-decoration:none;\">Ver categoría →</a>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<!-- ===================== RECORDATORIO DE OFERTA (OPCIONAL) ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"background-color:#F6F4F0; padding:32px 40px; text-align:center;\">\r\n      <p style=\"margin:0 0 16px 0; font-family:Arial, Helvetica, sans-serif; font-size:15px; color:#6E6A62;\">\r\n        Recuerda que tienes <strong style=\"color:#201E1A;\">10% off + envío gratis</strong> con el código <strong style=\"color:#1B3A5C;\">BIENVENIDO10</strong>.\r\n      </p>\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin:0 auto;\">\r\n        <tr>\r\n          <td style=\"background-color:#1B3A5C; border-radius:8px;\">\r\n            <a href=\"{{ shop.url }}\" style=\"display:inline-block; padding:14px 28px; font-family:Arial, Helvetica, sans-serif; font-size:14px; font-weight:bold; color:#FFFFFF; text-decoration:none;\">\r\n              Ver catálogo completo →\r\n            </a>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<!-- ===================== CANAL DE ATENCIÓN (OPCIONAL) ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"padding:32px 40px; text-align:center;\">\r\n      <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:13px; color:#6E6A62;\">\r\n        ¿No sabes qué buscas?\r\n        <a href=\"{{ shop.contact_url|default(shop.url) }}\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:13px; font-weight:bold; color:#1B3A5C; text-decoration:none;\">Habla con nuestro equipo →</a>\r\n      </p>\r\n    </td>\r\n  </tr>\r\n</table>', 'Catálogo\n¿Qué estás buscando?\nPara que te sea fácil encontrar lo que necesitas, aquí tienes un mapa rápido de nuestras categorías.\nHogar\nTodo lo que necesitas para tu espacio, en un solo lugar.\nVer categoría →\n \nTecnología y electrónica\nProductos confiables, con garantía y soporte incluido.\nVer categoría →\n \nCuidado personal\nSelección pensada para tu rutina diaria.\nVer categoría →\n \nAccesorios\nLos detalles que completan lo que ya tienes.\nVer categoría →\nRecuerda que tienes 10% off + envío gratis con el código BIENVENIDO10.\nVer catálogo completo →\n¿No sabes qué buscas?\nHabla con nuestro equipo →', NULL, 'prestashop_mail', 1, '2026-07-07 15:59:13', '2026-07-07 15:59:13'),
(12, 1, 1, NULL, 'order', 'Post-compra 04 - Cross-selling', '{{ customer.firstname|default(customer.name) }}, esto puede interesarte', 'mailsendvx_default', '<!-- ===================== HERO ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"padding:40px 40px 24px 40px;\">\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin-bottom:16px;\">\r\n        <tr>\r\n          <td style=\"background-color:rgba(27,58,92,0.08); border-radius:20px; padding:5px 12px; font-family:Arial, Helvetica, sans-serif; font-size:11px; font-weight:bold; color:#1B3A5C;\">\r\n            Recomendado para ti\r\n          </td>\r\n        </tr>\r\n      </table>\r\n\r\n      <h1 style=\"margin:0 0 14px 0; font-family:Arial, Helvetica, sans-serif; font-size:26px; line-height:1.3; font-weight:bold; color:#201E1A;\">\r\n        {{ customer.firstname|default(customer.name) }}, esto puede interesarte.\r\n      </h1>\r\n\r\n      <p style=\"margin:0; font-family:Arial, Helvetica, sans-serif; font-size:15px; line-height:1.6; color:#6E6A62;\">\r\n        A partir de tu compra reciente, seleccionamos algunos productos que combinan bien con lo que ya tienes.\r\n      </p>\r\n    </td>\r\n  </tr>\r\n</table>\r\n\r\n<!-- ===================== PRODUCTOS RECOMENDADOS (OBLIGATORIO SI HAY DATA) ===================== -->\r\n<!-- Sección protegida — si el pedido no tiene productos relacionados, no se dibuja nada acá -->\r\n{% if related_products is defined and related_products %}\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"padding:0 40px 24px 40px;\">\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n        <tr>\r\n          {% for product in related_products|slice(0, 3) %}\r\n          <td width=\"33%\" valign=\"top\" style=\"padding:0 6px;\">\r\n            <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"border:1px solid #E6E1D8; border-radius:12px;\">\r\n              <tr>\r\n                <td style=\"padding:15px; text-align:center;\">\r\n                  {% if product.image_url %}\r\n                  <img src=\"{{ product.image_url }}\" alt=\"{{ product.name }}\" width=\"135\" style=\"display:block; width:100%; max-width:135px; height:90px; object-fit:cover; border-radius:8px; margin:0 auto 12px auto;\">\r\n                  {% else %}\r\n                  <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin-bottom:12px;\"><tr><td style=\"height:90px; background-color:#F6F4F0; border-radius:8px;\">&nbsp;</td></tr></table>\r\n                  {% endif %}\r\n                  <p style=\"margin:0 0 6px 0; font-family:Arial, Helvetica, sans-serif; font-size:12px; font-weight:bold; color:#201E1A; line-height:1.3;\">{{ product.name }}</p>\r\n                  <p style=\"margin:0 0 10px 0; font-family:Arial, Helvetica, sans-serif; font-size:13px; font-weight:bold; color:#1B3A5C;\">${{ product.price }}</p>\r\n                  <a href=\"{{ product.url }}\" style=\"font-family:Arial, Helvetica, sans-serif; font-size:10.5px; font-weight:bold; color:#1B3A5C; text-decoration:none;\">Ver producto →</a>\r\n                </td>\r\n              </tr>\r\n            </table>\r\n          </td>\r\n          {% if not loop.last %}<td width=\"12\">&nbsp;</td>{% endif %}\r\n          {% endfor %}\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n</table>\r\n{% endif %}\r\n\r\n<!-- ===================== CTA ===================== -->\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n  <tr>\r\n    <td style=\"background-color:#F6F4F0; padding:32px 40px; text-align:center;\">\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"margin:0 auto;\">\r\n        <tr>\r\n          <td style=\"background-color:#1B3A5C; border-radius:8px;\">\r\n            <a href=\"{{ shop.url }}\" style=\"display:inline-block; padding:14px 28px; font-family:Arial, Helvetica, sans-serif; font-size:14px; font-weight:bold; color:#FFFFFF; text-decoration:none;\">\r\n              Explorar más recomendaciones →\r\n            </a>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n</table>', 'Recomendado para ti\n{{ customer.firstname|default(customer.name) }}, esto puede interesarte.\nA partir de tu compra reciente, seleccionamos algunos productos que combinan bien con lo que ya tienes.\n{% if related_products is defined and related_products %}\n{% for product in related_products|slice(0, 3) %}\n{% if product.image_url %}\n{% else %}\n \n{% endif %}\n{{ product.name }}\n${{ product.price }}\nVer producto →\n{% if not loop.last %} {% endif %}\n{% endfor %}\n{% endif %}\nExplorar más recomendaciones →', NULL, 'prestashop_mail', 1, '2026-07-07 16:15:37', '2026-07-07 16:15:37');

