--
-- Table structure for table `ps_mailsendvx_wrapper`
--

CREATE TABLE `ps_mailsendvx_wrapper` (
  `id_mailsendvx_wrapper` int(10) UNSIGNED NOT NULL,
  `id_shop` int(10) UNSIGNED NOT NULL DEFAULT 0,
  `id_lang` int(10) UNSIGNED NOT NULL DEFAULT 0,
  `name` varchar(128) NOT NULL,
  `html_content` mediumtext DEFAULT NULL,
  `text_content` mediumtext DEFAULT NULL,
  `date_add` datetime NOT NULL,
  `date_upd` datetime NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_uca1400_ai_ci;

--
-- Dumping data for table `ps_mailsendvx_wrapper`
