INSERT INTO `ps_mailsendvx_wrapper` (`id_mailsendvx_wrapper`, `id_shop`, `id_lang`, `name`, `html_content`, `text_content`, `date_add`, `date_upd`) VALUES
(1, 1, 1, 'mailsendvx_default', '<!DOCTYPE html>\r\n<html lang=\"es\">\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<title>{{ shop.name }}</title>\r\n</head>\r\n<body style=\"margin:0; padding:0; background-color:#F7F7F5;\">\r\n<table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background-color:#F7F7F5;\">\r\n<tr>\r\n<td align=\"center\" style=\"padding:24px 12px;\">\r\n\r\n<!--[if mso]>\r\n<table role=\"presentation\" width=\"600\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\"><tr><td>\r\n<![endif]-->\r\n<table role=\"presentation\" width=\"600\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"width:600px; max-width:600px; background-color:#FFFFFF;\">\r\n\r\n  <tr>\r\n    <td style=\"background-color:#1B3A5C; padding:24px 40px;\">\r\n      <table role=\"presentation\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n        <tr>\r\n          <td style=\"font-family:Arial, Helvetica, sans-serif; font-size:18px; font-weight:bold; color:#FFFFFF; letter-spacing:0.5px;\">\r\n            {{ shop.name }}\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n\r\n  <tr>\r\n    <td style=\"padding:0;\">\r\n      {{ mailsendvx_html_content|raw }}\r\n    </td>\r\n  </tr>\r\n\r\n  <tr>\r\n    <td style=\"background-color:#1B3A5C; padding:28px 40px;\">\r\n      <table role=\"presentation\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\">\r\n        <tr>\r\n          <td style=\"font-family:Arial, Helvetica, sans-serif; font-size:11px; line-height:18px; color:rgba(255,255,255,0.55); padding-bottom:16px;\">\r\n            {{ shop.name }} · Dirección de ejemplo 123, Ciudad<br>\r\n            hola@ejemplo.com · +00 000 000 000\r\n          </td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"font-family:Arial, Helvetica, sans-serif; font-size:11px; line-height:18px; color:rgba(255,255,255,0.55); padding-bottom:16px;\">\r\n            <a href=\"{{ shop.url }}\" style=\"color:rgba(255,255,255,0.55); text-decoration:none;\">Ir a la tienda</a>\r\n             · \r\n            <a href=\"{{ shop.unsubscribe_url }}\" style=\"color:rgba(255,255,255,0.55); text-decoration:none;\">Desuscribirse</a>\r\n             · \r\n            <a href=\"#\" style=\"color:rgba(255,255,255,0.55); text-decoration:none;\">Política de datos</a>\r\n          </td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"font-family:Arial, Helvetica, sans-serif; font-size:11px; line-height:18px; color:rgba(255,255,255,0.55);\">\r\n            <a href=\"#\" style=\"color:rgba(255,255,255,0.55); text-decoration:none;\">Facebook</a>\r\n             · \r\n            <a href=\"#\" style=\"color:rgba(255,255,255,0.55); text-decoration:none;\">Instagram</a>\r\n          </td>\r\n        </tr>\r\n      </table>\r\n    </td>\r\n  </tr>\r\n\r\n</table>\r\n<!--[if mso]>\r\n</td></tr></table>\r\n<![endif]-->\r\n\r\n</td>\r\n</tr>\r\n</table>\r\n</body>\r\n</html>', '{{ shop.name }}\n{{ shop.name }}\n{{ mailsendvx_text_content }}\n{{ shop.name }} · Dirección de ejemplo 123, Ciudad\nhola@ejemplo.com · +00 000 000 000\nIr a la tienda\n · \nDesuscribirse\n · \nPolítica de datos\nFacebook\n · \nInstagram', '2026-07-08 12:07:33', '2026-07-08 12:07:33');

